update esg.tb_workers_opinions_on_hazards_info 
set reviewer_opinion = #{content}
where write_year = #{writeYear}
  and doc_type = #{docType}
  and doc_no = #{docNo}
  and comp_id = #{compId}

UPDATE esg.tb_workers_opinions_on_hazards_info 
SET use_yn = 'N',
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND comp_id = #{compId}

		UPDATE esg.tb_workers_opinions_on_hazards_info 
