SELECT LPAD((COALESCE(MAX(SUBSTRING(experience_no, 1, 5)::INTEGER), 0) + 1)::TEXT, 5, '0') AS experienceNo FROM esg.tb_workers_opinions_on_hazards_experience WHERE write_year = #{writeYear} and doc_type = #{docType} and doc_no = #{docNo}
INSERT INTO esg.tb_workers_opinions_on_hazards_experience( write_year, doc_type, doc_no, reg_dt, content, use_yn, created_at, created_by, experience_no ) VALUES
(#{riskReportsSaveVO.writeYear}, #{riskReportsSaveVO.docType}, #{riskReportsSaveVO.docNo}, #{riskReportsSaveVO.regDt}, #{content}, 'Y', NOW(), #{riskReportsSaveVO.createdBy}, #{experienceNo} )
